/**
  * @brief 	motor param
  * @param   programNum ,uint8_t select
  * @retval none
  */
static void OLED_disp_motor_param(SYSTEM_MOTOR_PARAM* motorParam, ADJUST_select_NUM  selectNum )
{
	uint32_t temp,temp2;	
	if(motorParam->dir==EndoModePositionToggle)
	{
		 temp=speed_list[motorParam->toggleSpeedNum];
	}
	else temp=speed_list[motorParam->motorSpeedNum];		
	if(temp<1000)	
	{		
		OLED_ShowNum(40,4,temp,3,16,(selectNum!=ADJUST_MOTOR_PARAM_SPEED));	
		OLED_ShowChar(32,4,' ',16,(selectNum!=ADJUST_MOTOR_PARAM_SPEED));		
	}
	else
	{
		OLED_ShowNum(32,4,temp,4,16,(selectNum!=ADJUST_MOTOR_PARAM_SPEED));					
	}		
	if(motorParam->dir==EndoModePositionToggle)
	{
		temp=torque_list[motorParam->recTorqueThresholdNum];
	}	
  	else if( motorParam->dir==EndoModeTorqueATC)
	{	
		temp=torque_list[motorParam->atcTorqueThresholdNum];	
	}	
	else
	{
		temp=torque_list[motorParam->torqueThresholdNum];
	}
	temp2=(temp/10);
	OLED_ShowNum(40,24,temp2,1,16,(selectNum!=ADJUST_MOTOR_PARAM_TORQUE));//int
	OLED_ShowChar(48,24,'.',16,(selectNum!=ADJUST_MOTOR_PARAM_TORQUE));
	temp2=temp%10;
	OLED_ShowNum(52,24,temp2,1,16,(selectNum!=ADJUST_MOTOR_PARAM_TORQUE));	
	if(motorParam->dir==EndoModePositionToggle)
	{
		OLED_ShowString(48,44," REC ",16,(selectNum!=ADJUST_MOTOR_PARAM_DIRECTION));
		temp=abs(motorParam->reversePosition);		
		if(temp<100)
		{
			//OLED_ShowString(104,48,"  -",8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_RESERVE));
			OLED_ShowString(96,48,"   ",8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_RESERVE));
			OLED_ShowNum(114,48,temp,2,8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_RESERVE));
		}
		else
		{
			//OLED_ShowChar(110,48,'-',8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_RESERVE));
			OLED_ShowChar(102,48,' ',8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_RESERVE));
			OLED_ShowNum(108,48,temp,3,8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_RESERVE));
		}
		OLED_ShowChar(126,48,'/',8,1);
		temp=abs(motorParam->forwardPosition);	// angle
		if(temp<100)
		{			
			OLED_ShowNum(132,48,temp,2,8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_FORWARD));
			OLED_ShowChar(144,48,' ',8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_FORWARD));
		}
		else
		{
			OLED_ShowNum(132,48,temp,3,8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_FORWARD));
		}			
	}
	else if(motorParam->dir==EndoModeTorqueATC){//ATC
		OLED_ShowString(48,44," ATC ",16,(selectNum!=ADJUST_MOTOR_PARAM_DIRECTION));//angle
		temp=abs(motorParam->reversePosition);	// angle
		if(temp<100)
		{
//			OLED_ShowString(104,48,"  -",8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_RESERVE));
			OLED_ShowString(96,48,"   ",8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_RESERVE));
			OLED_ShowNum(114,48,temp,2,8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_RESERVE));
		}
		else
		{
//			OLED_ShowChar(110,48,'-',8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_RESERVE));
			OLED_ShowChar(102,48,' ',8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_RESERVE));
			OLED_ShowNum(108,48,temp,3,8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_RESERVE));
		}
		OLED_ShowChar(126,48,'/',8,1);
		temp=abs(motorParam->forwardPosition);
		if(temp<100)
		{
			OLED_ShowChar(144,48,' ',8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_FORWARD));
			OLED_ShowNum(132,48,temp,2,8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_FORWARD));
		}
		else
		{
			OLED_ShowNum(132,48,temp,3,8,(selectNum!=ADJUST_MOTOR_PARAM_ANGLE_FORWARD));
		}				
	}
	else if(motorParam->dir==EndoModeSpeedForward) {//forward
		OLED_ShowString(48,44," CW  ",16,(selectNum!=ADJUST_MOTOR_PARAM_DIRECTION));//angle
		temp=360;	// angle	
		OLED_ShowNum(120,48,temp,3,8,1);		
		OLED_ShowString(96,48,"    ",8,1);
		OLED_ShowString(138,48,"  ",8,1);	
	}
	else if(motorParam->dir==EndoModeSpeedReverse){//reserve
		OLED_ShowString(48,44," CCW ",16,(selectNum!=ADJUST_MOTOR_PARAM_DIRECTION));//闂傚倸鍊搁崐鎼佸磹閹间礁纾归柟闂寸绾惧綊鏌熼梻瀵割槮缁炬儳缍婇弻鐔兼⒒鐎靛壊妲紒鎯у⒔閹虫捇鈥旈崘顏佸亾閿濆簼绨奸柟鐧哥秮閺岋綁顢橀悙鎼闂侀潧妫欑敮鎺楋綖濠靛鏅查柛娑卞墮椤ユ艾鈹戞幊閸婃鎱ㄩ悜钘夌；婵炴垟鎳為崶顒佸仺缂佸瀵ч悗顒勬⒑閻熸澘鈷旂紒顕呭灦瀹曟垿骞囬悧鍫㈠幈闂佸綊鍋婇崹鎵閿曞倹鐓熼柕蹇曞閻撳吋鎱ㄦ繝鍕笡缂佹鍠栭崺鈧い鎺嗗亾妞ゎ厼娲╅ˇ褰掓煛娴ｅ摜啸缂佺姵绋戦埥澶娢熼搹鍦春濠碉紕鍋戦崐鏍偋濡ゅ啫鍨濈€光偓閳ь剟寮鈧、妤呭礋椤戣姤瀚奸梺鑽ゅТ濞层倕顕ｉ崼鏇炵闁挎繂顦伴悡娆撴煣韫囷絽浜濋悘蹇曟暬閺屽秷顧侀柛鎾村哺瀹曟瑨銇愰幒鎴犵厬闂佸憡鍔戦崝搴ㄥ汲閿旈敮鍋撶憴鍕婵炲眰鍊濊棢婵ǹ鍩栭崐鐢告煥濠靛棗鏆欏┑锛勫劋閹便劎鎲撮崟鍨杹濠殿喖锕ュ钘夌暦閻戠瓔鏁囬柣鎰絻椤棝姊绘担绛嬫綈闁烩剝娲熼、姘愁樄闁糕斂鍨归鍏煎緞婵犲孩缍傞梻渚€娼ч悧鍡椢涘畝鍕婵炲樊浜濋悡鐔兼煟濡搫甯犻柤鍓蹭邯閺屾盯寮懗顖氼伃闂佸疇顕х粔褰掔嵁閸ヮ剚鍋嬮柛顐犲灩楠炲秹姊绘担鍛婂暈闁割煈鍨跺畷鎰板冀椤愮喎浜炬慨妯煎亾鐎氾拷	
		temp=360;
		OLED_ShowNum(120,48,temp,3,8,1);		
		OLED_ShowString(96,48,"   -",8,1);
		OLED_ShowString(138,48,"  ",8,1);			
	}	
	#ifdef BLE_FUN
	DisplayBluetoothIcon(80,44, sys_param_un.device_param.BLE_Connect);
	#endif
	if((motorParam->dir)==EndoModeTorqueATC||(motorParam->dir)==EndoModePositionToggle)	
	{
		if(abs(motorParam->reversePosition)<abs(motorParam->forwardPosition))
		{
			OLED_Display_motorDirection(EndoModeTorqueATC);
		}
		else  OLED_Display_motorDirection(EndoModePositionToggle);
	}
	else OLED_Display_motorDirection(motorParam->dir);
}
/**
  * @brief 	home page
  * @param   programNum ,uint8_t select
  * @retval none
  */
static void OLED_Display_MAIN(unsigned short int programNum ,ADJUST_select_NUM selectNum)
{	
	if(programNum<10) //programNum=10 only apex mode
	{		
		if(programNum<9)//p1~9
		{
			OLED_ShowChar(0,4,' ',16,1);
			OLED_ShowChar(6,4,'P',16,1);	
			OLED_ShowNum(14,4,programNum+1,1,16,1);
			OLED_ShowChar(22,4,' ',16,1);
		}
		else //P10
		{
			OLED_ShowChar(2,4,'P',16,1);
			OLED_ShowNum(10,4,programNum+1,2,16,1);
		}	
		OLED_ShowString(72,4,"rpm",16,1);
		OLED_ShowChar(68,24,'N',16,1);	OLED_ShowChar(76,21,'.',16,1);	OLED_ShowString(80,24,"cm",16,1);	
		OLED_disp_motor_param(&motor_param_un.system_motor_pattern[programNum],selectNum);
	}
}
