						if(i<4)
						{
							disp_DrawColumn(x+1,y+1,18+20-i*6,0);
							disp_DrawColumn(x+2,y,20+20-i*6,0);
							disp_DrawColumn(x+3,y+1,18+20-i*6,0);
						}
